# Scratch: "அப்படியானால்" தொகுதி போன்றது
வானிலை = input("வானிலை எப்படி? (வெயில்/மழை): ")
if வானிலை == "வெயில்":
    print("வெளியே விளையாடலாம்!")
else:
    print("நிரலாக்கம் செய்யலாம்!")

# Scratch: "அப்படியானால் இல்லையென்றால் அப்படியானால்" தொகுதி போன்றது
மணி = int(input("இப்போது என்ன நேரம்? (0-23): "))
if மணி < 10:
    print("காலை வணக்கம்!")
elif மணி < 17:
    print("மதிய வணக்கம்!")
else:
    print("மாலை வணக்கம்!")

# Scratch: "திரும்பச்செய்" தொகுதி போன்றது
for எண்ணிக்கை in range(5):
    print(str(எண்ணிக்கை + 1) + " முறை: வணக்கம்!")
